import{_ as s,c as a,o as e,a5 as i}from"./chunks/framework.CByBVyi2.js";const u=JSON.parse('{"title":"🛠️ 一次与 disable-devtool 的“对抗”记录","description":"","frontmatter":{},"headers":[],"relativePath":"timeline/issue-87.md","filePath":"timeline/issue-87.md","lastUpdated":1775888756000}'),n={name:"timeline/issue-87.md"},l=i(`<h1 id="🛠️-一次与-disable-devtool-的-对抗-记录" tabindex="-1">🛠️ 一次与 disable-devtool 的“对抗”记录 <a class="header-anchor" href="#🛠️-一次与-disable-devtool-的-对抗-记录" aria-label="Permalink to &quot;🛠️ 一次与 disable-devtool 的“对抗”记录&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">原文地址</p><p><a href="https://github.com/jynba/jynba.github.io/issues/87" target="_blank" rel="noreferrer">🚀 一行代码搞定禁用web开发者工具：disable-devtool | GitHub</a></p></div><p>最近在调试一个网页时，遇到了比较“狠”的前端反调试机制。<br> 不仅禁止 F12、右键，还会在调试时<strong>直接关闭页面或强制跳转 404</strong>。</p><p>这篇文章记录我意外了解到这个 npm 库 <a href="https://github.com/theajack/disable-devtool" target="_blank" rel="noreferrer">disable-devtool</a> ，从“完全打不开 DevTools”到“定位并干掉跳转逻辑”的完整过程。</p><hr><h2 id="🚨-一、问题现象" tabindex="-1">🚨 一、问题现象 <a class="header-anchor" href="#🚨-一、问题现象" aria-label="Permalink to &quot;🚨 一、问题现象&quot;">​</a></h2><p>一开始的情况是这样的：</p><ul><li>打开 DevTools → 页面直接崩掉 / 白屏</li><li>点击 Resume（继续执行） → 页面直接关闭</li><li>禁用断点后 → 自动跳转：<a href="https://theajack.github.io/disable-devtool/404.html" target="_blank" rel="noreferrer">https://theajack.github.io/disable-devtool/404.html</a></li></ul><p>👉 很明显，这是一个典型的<strong>反调试保护</strong></p><hr><h2 id="🧠-二、初步判断-使用了-disable-devtool" tabindex="-1">🧠 二、初步判断：使用了 disable-devtool <a class="header-anchor" href="#🧠-二、初步判断-使用了-disable-devtool" aria-label="Permalink to &quot;🧠 二、初步判断：使用了 disable-devtool&quot;">​</a></h2><p>这个库的特点：</p><ul><li>检测 DevTools 是否打开</li><li>检测 debugger 停顿</li><li>检测窗口尺寸变化</li><li>触发： <ul><li>页面跳转</li><li>window.close()</li><li>自动关闭页面</li></ul></li></ul><h2 id="🧨-三、不断尝试" tabindex="-1">🧨 三、不断尝试 <a class="header-anchor" href="#🧨-三、不断尝试" aria-label="Permalink to &quot;🧨 三、不断尝试&quot;">​</a></h2><h3 id="❌-禁用断点" tabindex="-1">❌ 禁用断点 <a class="header-anchor" href="#❌-禁用断点" aria-label="Permalink to &quot;❌ 禁用断点&quot;">​</a></h3><p>ctrl+F8 结果： 👉 自动关闭页面 ❌</p><h3 id="❌-设置控制台绕过-close" tabindex="-1">❌ 设置控制台绕过 close() <a class="header-anchor" href="#❌-设置控制台绕过-close" aria-label="Permalink to &quot;❌ 设置控制台绕过 close()&quot;">​</a></h3><p>window.close = () =&gt; {}; 结果： 👉 页面直接跳转 404 ❌</p><h2 id="🔍-四、关键突破-定位跳转代码" tabindex="-1">🔍 四、关键突破：定位跳转代码 <a class="header-anchor" href="#🔍-四、关键突破-定位跳转代码" aria-label="Permalink to &quot;🔍 四、关键突破：定位跳转代码&quot;">​</a></h2><p>在 DevTools → Sources 中全局搜索： disable-devtool/404</p><p>最终定位到核心代码：</p><div class="language-javascript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setTimeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  window.location.href </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> f.timeOutUrl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">||</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://theajack.github.io/disable-devtool/404.html?h=&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">concat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">encodeURIComponent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(location.host))</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">500</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>🧱 四、最终稳定方案 在 Console 一次性执行：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 防止页面关闭</span></span>
<span class="line"><span>window.close = () =&gt; {};</span></span>
<span class="line"><span>// 禁止跳转</span></span>
<span class="line"><span>window.open = () =&gt; {};</span></span>
<span class="line"><span>location.assign = () =&gt; {};</span></span>
<span class="line"><span>location.replace = () =&gt; {};</span></span>
<span class="line"><span>// 禁止延迟跳转</span></span>
<span class="line"><span>window.setTimeout = () =&gt; {};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>👉 基本可以“免疫”这类反调试</p>`,25),t=[l];function p(o,r,h,d,c,b){return e(),a("div",null,t)}const m=s(n,[["render",p]]);export{u as __pageData,m as default};
